import requests
import json

class KongConfigurator:
    def __init__(self, admin_url):
        self.admin_url = admin_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({'Content-Type': 'application/json'})
    
    def create_service(self, service_name, url, protocol='http'):
        """Create a service in Kong"""
        service_data = {
            "name": service_name,
            "url": url,
            "protocol": protocol
        }
        
        response = self.session.post(f"{self.admin_url}/services", 
                                   data=json.dumps(service_data))
        return response.json()
    
    def create_route(self, service_id, hosts=None, paths=None, methods=None):
        """Create a route for a service"""
        route_data = {
            "service": {"id": service_id}
        }
        
        if hosts:
            route_data["hosts"] = hosts
        if paths:
            route_data["paths"] = paths
        if methods:
            route_data["methods"] = methods
            
        response = self.session.post(f"{self.admin_url}/routes", 
                                   data=json.dumps(route_data))
        return response.json()
    
    def create_upstream(self, upstream_name, algorithm='round-robin'):
        """Create an upstream in Kong"""
        upstream_data = {
            "name": upstream_name,
            "algorithm": algorithm
        }
        
        response = self.session.post(f"{self.admin_url}/upstreams", 
                                   data=json.dumps(upstream_data))
        return response.json()
    
    def create_target(self, upstream_id, target, weight=1):
        """Create a target for an upstream"""
        target_data = {
            "target": target,
            "weight": weight
        }
        
        response = self.session.post(f"{self.admin_url}/upstreams/{upstream_id}/targets", 
                                   data=json.dumps(target_data))
        return response.json()
    
    def create_plugin(self, service_id, plugin_name, config):
        """Create a plugin for a service"""
        plugin_data = {
            "name": plugin_name,
            "service": {"id": service_id},
            "config": config
        }
        
        response = self.session.post(f"{self.admin_url}/plugins", 
                                   data=json.dumps(plugin_data))
        return response.json()
    
    def get_service(self, service_id):
        """Get service details"""
        response = self.session.get(f"{self.admin_url}/services/{service_id}")
        return response.json()
    
    def get_route(self, route_id):
        """Get route details"""
        response = self.session.get(f"{self.admin_url}/routes/{route_id}")
        return response.json()
    
    def delete_service(self, service_id):
        """Delete a service"""
        response = self.session.delete(f"{self.admin_url}/services/{service_id}")
        return response.status_code == 204

